GUIJobExtractSmallItem = class("GUIJobExtractSmallItem", IGUIWindow)

function GUIJobExtractSmallItem:onLoad()

    self.isOpen = false
    self.content = self:getChildWindow(0, GUIType.Layout)
    self.ivImage = self:getChildWindow(0, GUIType.StaticImage, self.content)
    self.ivHave_Icon_Shade = self:getChildWindow(2, GUIType.StaticImage, self.content)    --已经抽过的职业显示选中状态
    self.ivHave_Icon_Shade:SetVisible(false)
end

function GUIJobExtractSmallItem:setItemData(item)
    self.id = item.id
    self.item = item
    self.ivImage:SetImage(item.image)
    self:setCardStatus(item.isOpen)
end

function GUIJobExtractSmallItem:setCardStatus(bool)

    self.isOpen = bool
    if self.isOpen then
        self.ivHave_Icon_Shade:SetVisible(true)
    else
        self.ivHave_Icon_Shade:SetVisible(false)
    end
end



